/*
 * trunc() test harness — prints (input_hex, output_hex) pairs.
 *
 * Build two versions:
 *   1. Linked with optimized Andes assembly trunc  (test_trunc_opt.elf)
 *   2. Linked with toolchain's default trunc        (test_trunc_ref.elf)
 * Run both, diff the output to find discrepancies.
 */

#include <math.h>
#include <stdint.h>
#include <stdio.h>
#include <float.h>

#ifdef EN_PERF
#define PF_COUNTER
#include "nds_pfcounter.h"
#endif

static inline uint64_t d2u(double d)
{
    union { double d; uint64_t u; } x;
    x.d = d;
    return x.u;
}

static inline double u2d(uint64_t u)
{
    union { double d; uint64_t u; } x;
    x.u = u;
    return x.d;
}

#ifdef EN_PERF
static volatile double g_acc;
#endif

static void emit(double x)
{
#ifdef EN_PERF
    volatile double vx = x;  /* prevent constant-folding of literal arguments */
    g_acc += trunc(vx);
#else
    double r = trunc(x);
    printf("%016llx %016llx\n", (unsigned long long)d2u(x), (unsigned long long)d2u(r));
#endif
}

static void emit_u(uint64_t bits)
{
    emit(u2d(bits));
}

/* ------------------------------------------------------------------ */
/* 100 representative test points                                      */
/* ------------------------------------------------------------------ */

static void test_representative_100(void)
{
    /* --- Section 1: Special IEEE 754 values (7) --- */
    emit(0.0);
    emit(-0.0);
    emit_u(0x7ff8000000000000ULL);  /* qNaN */
    emit_u(0x7ff0000000000001ULL);  /* sNaN */
    emit_u(0xfff8000000000000ULL);  /* -qNaN */
    emit_u(0x7ff0000000000000ULL);  /* +Inf */
    emit_u(0xfff0000000000000ULL);  /* -Inf */

    /* --- Section 2: Subnormal (denormal) values (6) --- */
    emit_u(0x0000000000000001ULL);  /* min positive subnormal: 2^-1074 */
    emit_u(0x8000000000000001ULL);  /* min negative subnormal */
    emit_u(0x0008000000000000ULL);  /* mid positive subnormal */
    emit_u(0x8008000000000000ULL);  /* mid negative subnormal */
    emit_u(0x000fffffffffffffULL);  /* max subnormal: just below DBL_MIN */
    emit_u(0x800fffffffffffffULL);  /* max negative subnormal */

    /* --- Section 3: Normal boundary values (4) --- */
    emit(DBL_MIN);                  /* 2^-1022, smallest positive normal */
    emit(-DBL_MIN);
    emit(DBL_MAX);                  /* largest finite double */
    emit(-DBL_MAX);

    /* --- Section 4: Near 1.0 ULP density (8) --- */
    emit_u(0x3fefffffffffffffULL);  /* one ULP below 1.0 */
    emit(1.0);
    emit_u(0x3ff0000000000001ULL);  /* one ULP above 1.0 */
    emit_u(0x3feffffffffffffeULL);  /* two ULPs below 1.0 */
    emit_u(0x3ff0000000000002ULL);  /* two ULPs above 1.0 */
    emit(-1.0);
    emit_u(0xbfefffffffffffffULL);  /* one ULP toward zero from -1.0 */
    emit_u(0xbff0000000000001ULL);  /* one ULP away from zero from -1.0 */

    /* --- Section 5: Half-integer values (12) --- */
    /* trunc(n+0.5) = n, trunc(-(n+0.5)) = -n */
    emit(0.5);
    emit(-0.5);
    emit(1.5);
    emit(-1.5);
    emit(2.5);
    emit(-2.5);
    emit(3.5);
    emit(-3.5);
    emit(4.5);
    emit(-4.5);
    emit(100.5);
    emit(-100.5);

    /* --- Section 6: Small fractional values in (0,1) and (-1,0) (10) --- */
    /* All should truncate to +/-0.0 */
    emit(0.1);
    emit(0.25);
    emit(0.3);
    emit(0.49999999999999994);       /* just below 0.5 */
    emit(0.9999999999999998);        /* just below 1.0 */
    emit(-0.1);
    emit(-0.25);
    emit(-0.3);
    emit(-0.49999999999999994);      /* just above -0.5 */
    emit(-0.9999999999999998);       /* just above -1.0 */

    /* --- Section 7: Small integer values +/- (8) --- */
    /* trunc of exact integers should return the input unchanged */
    emit(2.0);
    emit(-2.0);
    emit(3.0);
    emit(-3.0);
    emit(5.0);
    emit(-5.0);
    emit(10.0);
    emit(-10.0);

    /* --- Section 8: Near-integer ULP boundaries (15) --- */
    /* 1 ULP below n.0, exact n.0 (already covered), 1 ULP above n.0 */
    /* n=2: 2.0 = 0x4000000000000000 */
    emit_u(0x3fffffffffffffffULL);  /* one ULP below 2.0 (= largest value < 2) */
    emit_u(0x4000000000000001ULL);  /* one ULP above 2.0 */
    /* n=3: 3.0 = 0x4008000000000000 */
    emit_u(0x4007ffffffffffffULL);  /* one ULP below 3.0 */
    emit_u(0x4008000000000001ULL);  /* one ULP above 3.0 */
    /* n=4: 4.0 = 0x4010000000000000 */
    emit_u(0x400fffffffffffffULL);  /* one ULP below 4.0 */
    emit_u(0x4010000000000001ULL);  /* one ULP above 4.0 */
    /* n=8: 8.0 = 0x4020000000000000 */
    emit_u(0x401fffffffffffffULL);  /* one ULP below 8.0 */
    emit_u(0x4020000000000001ULL);  /* one ULP above 8.0 */
    /* n=16: 16.0 = 0x4030000000000000 */
    emit_u(0x402fffffffffffffULL);  /* one ULP below 16.0 */
    emit_u(0x4030000000000001ULL);  /* one ULP above 16.0 */
    /* n=-2 */
    emit_u(0xbfffffffffffffffULL);  /* one ULP toward zero from -2.0 */
    emit_u(0xc000000000000001ULL);  /* one ULP away from zero from -2.0 */
    /* n=-4 */
    emit_u(0xc00fffffffffffffULL);  /* one ULP toward zero from -4.0 */
    emit_u(0xc010000000000001ULL);  /* one ULP away from zero from -4.0 */
    /* n=-8 */
    emit_u(0xc01fffffffffffffULL);  /* one ULP toward zero from -8.0 */

    /* --- Section 9: Large values where double loses fractional bits (15) --- */
    /* At 2^52, the ULP is 1.0 so all values are integers; trunc is identity */
    emit_u(0x4330000000000000ULL);  /* 2^52 = 4503599627370496.0 */
    emit_u(0x4330000000000001ULL);  /* 2^52 + 1 */
    emit_u(0x433fffffffffffffULL);  /* just below 2^53 */
    emit_u(0x4340000000000000ULL);  /* 2^53 = 9007199254740992.0 */
    emit_u(0x4340000000000001ULL);  /* 2^53 + 1 (ULP = 2 now) */
    emit_u(0xc330000000000000ULL);  /* -2^52 */
    emit_u(0xc340000000000000ULL);  /* -2^53 */
    emit(1.0e15);                   /* large but representable integer */
    emit(-1.0e15);
    emit(1.0e16);
    emit(-1.0e16);
    emit(1.0e100);                  /* astronomically large */
    emit(-1.0e100);
    emit(1.0e300);
    emit(-1.0e300);

    /* --- Section 10: Mixed fractional cases across ranges (15) --- */
    /* Values with fractional parts at various magnitudes */
    emit(1.1);
    emit(-1.1);
    emit(1.9);
    emit(-1.9);
    emit(7.7);
    emit(-7.7);
    emit(127.999);
    emit(-127.999);
    emit(1000.0001);
    emit(-1000.0001);
    emit(1048576.5);                /* 2^20 + 0.5 */
    emit(-1048576.5);               /* -(2^20 + 0.5) */
    emit(2097151.9999999998);       /* just below 2^21 */
    emit(4503599627370495.5);       /* 2^52 - 0.5: last representable non-integer */
    emit(-4503599627370495.5);      /* -(2^52 - 0.5) */
}

/* ------------------------------------------------------------------ */

#ifndef EN_PERF
/* Sweep [0, 10] in 100 steps and [-10, 0] in 100 steps */
static void test_sweep(void)
{
    double hi = 10.0;
    int nsteps = 100;
    double step = hi / (double)nsteps;

    /* [0, 10] */
    for (int i = 0; i <= nsteps; i++)
        emit((double)i * step);

    /* [-10, 0] */
    for (int i = 0; i <= nsteps; i++)
        emit(-hi + (double)i * step);
}

/* Sample [0, 10] every ~0.05 (200 points) */
static void test_exhaustive_small(void)
{
    double hi = 10.0;
    int nsteps = 200;
    double step = hi / (double)nsteps;

    for (int i = 0; i <= nsteps; i++)
        emit((double)i * step);
}
#endif

/* ------------------------------------------------------------------ */

int main(void)
{
#ifdef EN_PERF
    startPFM;
    test_representative_100();
    stopPFM;
    readResult();
    printf("perf: %016llx\n", (unsigned long long)d2u((double)g_acc));
#else
    test_representative_100();
    test_sweep();
    test_exhaustive_small();
#endif
    return 0;
}

